   248→"use client";
   249→
   250→import {
   251→      createContext,
   252→      useContext,
   253→      useState,
   254→      useEffect,
   255→      useCallback,
   256→      useRef,
   257→      type ReactNode,
   258→} from "react";
   259→import { createClient } from "@/lib/supabase/client";
   260→import { toast } from "sonner";
   261→import type {
   262→      User,
   263→      Session,
   264→      SignInWithPasswordCredentials,
   265→} from "@supabase/supabase-js";
   266→import type { Profile } from "@/lib/types/index";
   267→
   268→// ─────────────────────────────────────────────
   269→// Types
   270→// ─────────────────────────────────────────────
   271→
   272→interface AuthContextType {
   273→      user: User | null;
   274→      profile: Profile | null;
   275→      session: Session | null;
   276→      isLoading: boolean;
   277→      isLoggedIn: boolean;
   278→      signIn: (credentials: SignInWithPasswordCredentials) => Promise<void>;
   279→      signUp: (credentials: SignUpCredentials) => Promise<void>;
   280→      signOut: () => Promise<void>;
   281→      updateProfile: (updates: ProfileUpdates) => Promise<Profile | null>;
   282→      refreshProfile: () => Promise<void>;
   283→}
   284→
   285→interface SignUpCredentials {
   286→      email: string;
   287→      password: string;
   288→      user_name?: string;
   289→}
   290→
   291→interface ProfileUpdates {
   292→      user_name?: string | null;
   293→      role?: string | null;
   294→      avatar_url?: string | null;
   295→      followers?: number | null;
   296→}
   297→
   298→// ─────────────────────────────────────────────
   299→// Helpers
   300→// ─────────────────────────────────────────────
   301→
   302→/** Extracts a display name from Supabase auth user metadata. */
   303→function extractDisplayName(user: User | null): string | null {
   304→      const meta = user?.user_metadata as Record<string, unknown> | undefined;
   305→      for (const key of ["name", "full_name", "first_name"]) {
   306→            const val = meta?.[key];
   307→            if (typeof val === "string" && val.trim()) return val.trim();
   308→      }
   309→      return null;
   310→}
   311→
   312→// ─────────────────────────────────────────────
   313→// Context
   314→// ─────────────────────────────────────────────
   315→
   316→const AuthContext = createContext<AuthContextType | undefined>(undefined);
   317→
   318→// ─────────────────────────────────────────────
   319→// Provider
   320→// ─────────────────────────────────────────────
   321→
   322→export function AuthProvider({ children }: { children: ReactNode }) {
   323→      const supabase = createClient();
   324→
   325→      const [user, setUser] = useState<User | null>(null);
   326→      const [profile, setProfile] = useState<Profile | null>(null);
   327→      const [session, setSession] = useState<Session | null>(null);
   328→      const [isLoading, setIsLoading] = useState(true);
   329→
   330→      // Prevents fetchProfile from being called concurrently for the same user.
   331→      const isFetchingProfile = useRef(false);
   332→
   333→      // ─── fetchProfile ───────────────────────────
   334→
   335→      /**
   336→       * Fetches or auto-creates the profile row for the given userId.
   337→       *
   338→       * @param userId   - Supabase auth UID
   339→       * @param authUser - The User object already in hand (avoids a redundant getUser() call)
   340→       */
   341→      const fetchProfile = useCallback(
   342→            async (userId: string, authUser: User | null) => {
   343→                  // Guard against concurrent calls (e.g. rapid auth state changes)
   344→                  if (isFetchingProfile.current) return;
   345→                  isFetchingProfile.current = true;
   346→
   347→                  try {
   348→                        const { data, error } = await supabase
   349→                              .from("profiles")
   350→                              .select("*")
   351→                              .eq("id", userId)
   352→                              .single();
   353→
   354→                        // ✅ Happy path — profile row exists
   355→                        if (!error && data) {
   356→                              setProfile(data as Profile);
   357→                              return;
   358→                        }
   359→
   360→                        // 🔧 Profile row missing — auto-create it
   361→                        if (error.code === "PGRST116") {
   362→                              const userName = extractDisplayName(authUser);
   363→
   364→                              const { data: created, error: createError } = await supabase
   365→                                    .from("profiles")
   366→                                    .insert([{ id: userId, user_name: userName }])
   367→                                    .select()
   368→                                    .single();
   369→
   370→                              if (createError) {
   371→                                    console.error("[AuthContext] Profile creation failed:", createError);
   372→                                    toast.error("Failed to set up your profile. Please refresh.");
   373→                                    setProfile(null);
   374→                                    return;
   375→                              }
   376→
   377→                              setProfile(created as Profile);
   378→                              return;
   379→                        }
   380→
   381→                        // ❌ Unexpected DB error
   382→                        console.error("[AuthContext] Profile fetch failed:", error);
   383→                        toast.error("Failed to load your profile. Please refresh.");
   384→                        setProfile(null);
   385→                  } finally {
   386→                        isFetchingProfile.current = false;
   387→                  }
   388→            },
   389→            [supabase]
   390→      );
   391→
   392→      // ─── Bootstrap session on mount ─────────────
   393→
   394→      useEffect(() => {
   395→            let mounted = true;
   396→
   397→            const bootstrap = async () => {
   398→                  const {
   399→                        data: { session },
   400→                        error,
   401→                  } = await supabase.auth.getSession();
   402→
   403→                  if (error) {
   404→                        console.error("[AuthContext] getSession error:", error);
   405→                  }
   406→
   407→                  if (!mounted) return;
   408→
   409→                  setSession(session);
   410→                  setUser(session?.user ?? null);
   411→
   412→                  if (session?.user) {
   413→                        await fetchProfile(session.user.id, session.user);
   414→                  }
   415→
   416→                  setIsLoading(false);
   417→            };
   418→
   419→            bootstrap();
   420→
   421→            // ─── Auth state listener ───────────────────
   422→
   423→            const {
   424→                  data: { subscription },
   425→            } = supabase.auth.onAuthStateChange(async (event, session) => {
   426→                  if (!mounted) return;
   427→
   428→                  // Ignore token refreshes — profile hasn't changed
   429→                  if (event === "TOKEN_REFRESHED") return;
   430→
   431→                  setSession(session);
   432→                  setUser(session?.user ?? null);
   433→
   434→                  if (session?.user) {
   435→                        await fetchProfile(session.user.id, session.user);
   436→                  } else {
   437→                        setProfile(null);
   438→                  }
   439→            });
   440→
   441→            return () => {
   442→                  mounted = false;
   443→                  subscription.unsubscribe();
   444→            };
   445→      }, [fetchProfile, supabase]);
   446→
   447→      // ─── Auth actions ────────────────────────────
   448→
   449→      const signIn = async (credentials: SignInWithPasswordCredentials) => {
   450→            const { error } = await supabase.auth.signInWithPassword(credentials);
   451→            if (error) throw error;
   452→            toast.success("Signed in successfully!");
   453→      };
   454→
   455→      const signUp = async ({ email, password, user_name }: SignUpCredentials) => {
   456→            const { data, error } = await supabase.auth.signUp({
   457→                  email,
   458→                  password,
   459→                  options: {
   460→                        data: { name: user_name ?? null },
   461→                  },
   462→            });
   463→
   464→            if (error) throw error;
   465→
   466→            // Eagerly create the profiles row so it exists before the first fetchProfile call.
   467→            const userId = data?.user?.id;
   468→            if (userId) {
   469→                  const { error: upsertError } = await supabase
   470→                        .from("profiles")
   471→                        .upsert({ id: userId, user_name: user_name ?? null });
   472→
   473→                  if (upsertError) {
   474→                        // Non-fatal — fetchProfile will auto-create it on first load.
   475→                        console.error("[AuthContext] Profile upsert after signUp failed:", upsertError);
   476→                  }
   477→            }
   478→
   479→            toast.success("Account created! Check your email to confirm.");
   480→      };
   481→
   482→      const signOut = async () => {
   483→            const { error } = await supabase.auth.signOut();
   484→            if (error) {
   485→                  console.error("[AuthContext] signOut error:", error);
   486→                  toast.error("Sign out failed. Please try again.");
   487→                  return;
   488→            }
   489→            // State is cleared by the onAuthStateChange listener — no need to do it here.
   490→            toast.success("Signed out.");
   491→      };
   492→
   493→      // ─── Profile mutation ────────────────────────
   494→
   495→      const updateProfile = async (updates: ProfileUpdates): Promise<Profile | null> => {
   496→            if (!user) throw new Error("[AuthContext] updateProfile called without an authenticated user.");
   497→
   498→            // Update auth metadata if display name changed
   499→            if (updates.user_name !== undefined) {
   500→                  const { error: metaError } = await supabase.auth.updateUser({
   501→                        data: { name: updates.user_name },
   502→                  });
   503→                  if (metaError) {
   504→                        // Non-fatal — profiles table is the source of truth
   505→                        console.error("[AuthContext] Auth metadata update failed:", metaError);
   506→                  }
   507→            }
   508→
   509→            const { data: updated, error } = await supabase
   510→                  .from("profiles")
   511→                  .upsert({ id: user.id, ...updates })
   512→                  .select()
   513→                  .single();
   514→
   515→            if (error) {
   516→                  console.error("[AuthContext] Profile update failed:", error);
   517→                  throw error;
   518→            }
   519→
   520→            // Merge a resolved display name so consumers always have `profile.name`
   521→            const merged: Profile = {
   522→                  ...updated,
   523→                  name:
   524→                        updated.user_name ??
   525→                        extractDisplayName(user) ??
   526→                        user.email?.split("@")[0] ??
   527→                        null,
   528→            };
   529→
   530→            setProfile(merged);
   531→            return merged;
   532→      };
   533→
   534→      // ─── refreshProfile ──────────────────────────
   535→
   536→      const refreshProfile = useCallback(async () => {
   537→            if (user) await fetchProfile(user.id, user);
   538→      }, [user, fetchProfile]);
   539→
   540→      // ─── Context value ───────────────────────────
   541→
   542→      const value: AuthContextType = {
   543→            user,
   544→            profile,
   545→            session,
   546→            isLoading,
   547→            isLoggedIn: !!session,
   548→            signIn,
   549→            signUp,
   550→            signOut,
   551→            updateProfile,
   552→            refreshProfile,
   553→      };
   554→
   555→      return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
   556→}
   557→
   558→// ─────────────────────────────────────────────
   559→// Hook
   560→// ─────────────────────────────────────────────
   561→
   562→export function useAuth() {
   563→      const ctx = useContext(AuthContext);
   564→      if (!ctx) throw new Error("useAuth must be used inside <AuthProvider>");
   565→      return ctx;
   566→}

